// Source: thesvg.org (cdn.jsdelivr.net/gh/glincker/thesvg), byte-for-byte except:
//  - the `<?xml ?>` prolog is dropped (inline SVG-in-HTML can't carry it), and
//  - every internal id is prefixed with the icon's slug (e.g. `edge-a`). The hero
//    stacks all marks in one DOM, and many share generic gradient ids (a, b, …);
//    namespacing keeps their gradients from clobbering each other. Appearance is
//    unchanged — no fills or dimensions are edited.
//
// Sizing and light/dark colour live entirely in CSS (`.brand-mark` / `.mono` in
// index.css): coloured marks keep their palette; monochrome marks (mono: true)
// follow the text colour.
//
// To add a mark: paste the raw <svg> from thesvg.org, drop the xml prolog,
// prefix its ids with the slug, and set `mono: true` if it's officially B/W.

export type Brand = { art?: string; name: string; svg: string; mono?: boolean; weight?: number };

